71	/// Commands sent to the injection thread via mpsc channel.
72	pub enum MacroCmd {
73	    /// Execute a key sequence. Keys are evdev key names (e.g., "KEY_UP").
74	    Execute {
75	        /// Ordered list of keys to press, with optional per-key timing overrides.
76	        keys: Vec<KeyStep>,
77	        /// Global timing defaults (from config) to use when per-key override is absent.
78	        default_dwell_ms: u64,
79	        default_gap_ms: u64,
80	    },
81	    /// Signal the injection thread to exit cleanly.
82	    Shutdown,
83	}
84	
85	/// One step in a macro sequence.
86	pub struct KeyStep {
87	    /// evdev key name to press (e.g. `"KEY_UP"`); parsed by `ptt::parse_key_code` at inject time.
88	    pub key_name: String,
89	    /// Per-key dwell override (milliseconds). None = use global default.
90	    pub dwell_ms: Option<u64>,
91	    /// Per-key gap override (milliseconds). None = use global default.
92	    pub gap_ms: Option<u64>,
93	}
94	
95	impl KeyStep {
96	    /// Convert a [`crate::config::KeyAction`] from the YAML config into a `KeyStep`.
97	    pub fn from_config(action: &crate::config::KeyAction) -> Self {
98	        KeyStep {
99	            key_name: action.key.clone(),
100	            dwell_ms: action.dwell_ms,
101	            gap_ms: action.gap_ms,
102	        }
103	    }
104	}
