106	/// Open a keyboard-only uinput VirtualDevice named "vibe-attack" (D-05, MCRO-05).
107	///
108	/// Returns DaemonError::UinputPermissionDenied on EACCES — the Display message
109	/// is the exact actionable error the user sees (D-15).
110	///
111	/// Pitfall 3 mitigation: error message specifies 'input' group, not 'uinput' group,
112	/// because systemd v258+ ignores non-system groups in udev rules.
113	pub fn open_uinput_device() -> Result<evdev::uinput::VirtualDevice> {
114	    let mut keys = AttributeSet::<KeyCode>::new();
115	    for &k in VIRTUAL_KEYBOARD_KEYS {
116	        keys.insert(k);
117	    }
118	
119	    VirtualDevice::builder()
120	        .map_err(|e| {
121	            if e.kind() == std::io::ErrorKind::PermissionDenied {
122	                anyhow::anyhow!("{}", crate::error::DaemonError::UinputPermissionDenied)
123	            } else {
124	                anyhow::anyhow!("Failed to open /dev/uinput: {e}")
125	            }
126	        })?
127	        .name("vibe-attack")
128	        .with_keys(&keys)
129	        .map_err(|e| anyhow::anyhow!("Failed to configure virtual keys: {e}"))?
130	        .build()
131	        .map_err(|e| {
132	            if e.kind() == std::io::ErrorKind::PermissionDenied {
133	                anyhow::anyhow!("{}", crate::error::DaemonError::UinputPermissionDenied)
134	            } else {
135	                anyhow::anyhow!("Failed to build VirtualDevice: {e}")
136	            }
137	        })
138	}
139	
140	/// Emit a single key press-hold-release sequence (MCRO-01, MCRO-02).
141	///
142	/// Sequence: KEY_DOWN → sleep(dwell_ms) → KEY_UP → sleep(gap_ms)
143	///
144	/// CRITICAL — Pitfall 6 from RESEARCH.md:
145	/// `VirtualDevice::emit()` automatically appends SYN_REPORT. Do NOT pass SYN_REPORT
146	/// manually — that sends a double-SYN and garbles the event stream.
147	fn emit_key_action(
148	    device: &mut evdev::uinput::VirtualDevice,
149	    key: KeyCode,
150	    dwell_ms: u64,
151	    gap_ms: u64,
152	) -> Result<()> {
153	    use evdev::EventType;
154	
155	    // KEY_DOWN (value = 1)
156	    device
157	        .emit(&[InputEvent::new(EventType::KEY.0, key.0, 1)])
158	        .map_err(|e| anyhow::anyhow!("Failed to emit KEY_DOWN for {key:?}: {e}"))?;
159	
160	    std::thread::sleep(Duration::from_millis(dwell_ms));
161	
162	    // KEY_UP (value = 0)
163	    device
164	        .emit(&[InputEvent::new(EventType::KEY.0, key.0, 0)])
165	        .map_err(|e| anyhow::anyhow!("Failed to emit KEY_UP for {key:?}: {e}"))?;
166	
167	    std::thread::sleep(Duration::from_millis(gap_ms));
168	
169	    tracing::trace!(key = ?key, dwell_ms, gap_ms, "Key action emitted");
170	    Ok(())
171	}
172	
173	/// Spawn the injection thread on a dedicated OS thread (D-07).
174	///
175	/// The thread owns the VirtualDevice and executes MacroCmd::Execute messages
176	/// received on the channel. Exits on MacroCmd::Shutdown or channel disconnect.
177	///
178	/// Use `std::thread::spawn` (NOT `tokio::task::spawn_blocking`): this thread is
179	/// long-lived and uses std::thread::sleep for precise timing (D-07).
180	pub fn spawn_injection_thread(
181	    mut device: evdev::uinput::VirtualDevice,
182	    rx: mpsc::Receiver<MacroCmd>,
183	) -> std::thread::JoinHandle<()> {
184	    std::thread::spawn(move || {
185	        tracing::info!("Injection thread started");
186	        loop {
187	            match rx.recv() {
188	                Ok(MacroCmd::Execute {
189	                    keys,
190	                    default_dwell_ms,
191	                    default_gap_ms,
192	                }) => {
193	                    tracing::debug!("Executing macro with {} key(s)", keys.len());
194	                    for step in &keys {
195	                        let key = match crate::input::ptt::parse_key_code(&step.key_name) {
196	                            Ok(k) => k,
197	                            Err(e) => {
198	                                tracing::error!("Invalid key '{}': {e}", step.key_name);
199	                                continue;
200	                            }
201	                        };
202	                        let dwell = step.dwell_ms.unwrap_or(default_dwell_ms);
203	                        let gap = step.gap_ms.unwrap_or(default_gap_ms);
204	                        if let Err(e) = emit_key_action(&mut device, key, dwell, gap) {
205	                            tracing::error!("Inject error: {e}");
206	                        }
207	                    }
208	                }
209	                Ok(MacroCmd::Shutdown) => {
210	                    tracing::info!("Injection thread: shutdown received, exiting");
211	                    break;
212	                }
213	                Err(_) => {
214	                    // Channel disconnected — daemon is shutting down
215	                    tracing::debug!("Injection thread: channel closed, exiting");
216	                    break;
217	                }
218	            }
219	        }
220	        tracing::info!("Injection thread stopped");
221	    })
222	}
